INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 1, 126401, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 2002, 2, 1, "2023/09/22 14:59:59", "クローチェ", 10001, 1.47, "2023/06/30 12:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 1, 126401, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 2002, 1, 2, "2023/09/22 14:59:59", "クローチェ", 10002, 2.15, "2023/06/30 12:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 1, 126501, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 2002, 2, 1, "2023/09/22 14:59:59", "ライラエル", 10003, 0.0, "2023/06/30 12:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 1, 126501, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 2002, 1, 2, "2023/09/22 14:59:59", "ライラエル", 10004, 0.0, "2023/06/30 12:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 2, 127702, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 2002, 2, 1, "2023/12/22 14:59:59", "リンド", 10005, 0.0, "2023/09/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 2, 127702, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 2002, 2, 2, "2023/12/22 14:59:59", "リンド", 10006, 0.0, "2023/09/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 2, 127802, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 2002, 1, 1, "2023/12/22 14:59:59", "ヴルム", 10007, 0.0, "2023/09/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 2, 127802, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2002, 1, 2, "2023/12/22 14:59:59", "ヴルム", 10008, 6.5, "2023/09/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 3, 129602, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 2002, 1, 1, "2024/03/22 14:59:59", "アネモネ", 10009, 0.0, "2023/12/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 3, 129602, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2002, 1, 2, "2024/03/22 14:59:59", "アネモネ", 10010, 0.0, "2023/12/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 3, 129701, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 2002, 1, 1, "2024/03/22 14:59:59", "ネフィ=ネラ", 10011, 0.0, "2023/12/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 3, 129701, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2002, 1, 2, "2024/03/22 14:59:59", "ネフィ=ネラ", 10012, 6.2, "2023/12/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 4, 130301, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 2002, 5, 1, "2024/06/22 14:59:59", "カノン", 10013, 3.1, "2024/03/15 15:00:00", 3);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 4, 130301, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2002, 2, 2, "2024/06/22 14:59:59", "カノン", 10014, 6.15, "2024/03/15 15:00:00", 3);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 4, 130401, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 2002, 2, 1, "2024/06/22 14:59:59", "ナーナ", 10015, 0.0, "2024/03/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 4, 130401, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2002, 1, 2, "2024/06/22 14:59:59", "ナーナ", 10016, 3.35, "2024/03/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 5, 130502, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 2002, 1, 1, "2024/09/22 14:59:59", "ホウオウ", 10017, 0.0, "2024/06/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 5, 130502, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2002, 1, 2, "2024/09/22 14:59:59", "ホウオウ", 10018, 3.18, "2024/06/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 5, 130503, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 2002, 4, 3, "2024/09/22 14:59:59", "ホウオウ", 10019, 0.0, "2024/06/15 15:00:00", 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 5, 123301, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 2002, 2, 1, "2024/09/22 14:59:59", "ネア", 10020, 4.9, "2024/06/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 5, 123301, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2002, 2, 2, "2024/09/22 14:59:59", "ネア", 10021, 4.8, "2024/06/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 6, 133301, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 2002, 1, 1, "2024/12/22 14:59:59", "カリザ", 10022, 4.922, "2024/09/15 15:00:00", 3);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 6, 133301, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2002, 5, 2, "2024/12/22 14:59:59", "カリザ", 10023, 9.638, "2024/09/15 15:00:00", 3);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 6, 133401, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 2002, 2, 1, "2024/12/22 14:59:59", "ミーア", 10024, 2.88, "2024/09/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 6, 133401, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2002, 1, 2, "2024/12/22 14:59:59", "ミーア", 10025, 4.818, "2024/09/15 15:00:00", 5);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 7, 133002, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 2002, 1, 1, "2025/03/22 14:59:59", "グレイス", 10026, 1.78, "2024/12/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 7, 133002, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2002, 7, 2, "2025/03/22 14:59:59", "グレイス", 10027, 6.15, "2024/12/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 7, 133102, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 2002, 2, 1, "2025/03/22 14:59:59", "ヴァイオレット", 10028, 4.28, "2024/12/15 15:00:00", 6);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 7, 133102, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2002, 1, 2, "2025/03/22 14:59:59", "ヴァイオレット", 10029, 0.0, "2024/12/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 8, 136902, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 2002, 1, 1, "2025/06/23 14:59:59", "ルルィ", 10030, 5.53, "2025/03/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 8, 136902, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2002, 7, 2, "2025/06/23 14:59:59", "ルルィ", 10031, 6.05, "2025/03/15 15:00:00", 9);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 8, 137001, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 2002, 1, 1, "2025/06/23 14:59:59", "デュラン", 10032, 0.0, "2025/03/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 8, 137001, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2002, 1, 2, "2025/06/23 14:59:59", "デュラン", 10033, 0.0, "2025/03/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 9, 135902, "おう\n好きなもん持ってきな", 2002, 2, 1, "2025/09/23 14:59:59", "サツキ", 10034, 0.0, "2025/06/16 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 9, 135902, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2002, 6, 2, "2025/09/23 14:59:59", "サツキ", 10035, 4.935, "2025/06/16 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 9, 135802, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 2002, 5, 1, "2025/09/23 14:59:59", "ユキノ", 10036, 7.441, "2025/06/16 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 9, 135802, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2002, 7, 2, "2025/09/23 14:59:59", "ユキノ", 10037, 0.0, "2025/06/16 15:00:00", 7);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 10, 130901, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 2002, 2, 1, "2025/12/22 14:59:59", "クルル", 10038, 2.295, "2025/09/16 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 10, 130901, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2002, 6, 2, "2025/12/22 14:59:59", "クルル", 10039, 6.281, "2025/09/16 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 10, 137701, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 2002, 1, 1, "2025/12/22 14:59:59", "ヴォルガーノ", 10040, 5.549, "2025/09/16 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 10, 137701, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2002, 6, 2, "2025/12/22 14:59:59", "ヴォルガーノ", 10041, 2.64, "2025/09/16 15:00:00", 3);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 11, 132801, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 2002, 4, 1, "2026/03/23 11:59:59", "ライラエル", 10042, 7.642, "2025/12/15 15:00:00", 7);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 11, 132802, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2002, 1, 2, "2026/03/23 11:59:59", "ライラエル", 10043, 0.0, "2025/12/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 11, 134502, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 2002, 1, 1, "2026/03/23 11:59:59", "クローチェ", 10044, 0.0, "2025/12/15 15:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 11, 134501, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2002, 1, 2, "2026/03/23 11:59:59", "クローチェ", 10045, 3.72, "2025/12/15 15:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 12, 138201, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 2002, 1, 1, "2026/06/22 11:59:59", "ネフィ＝ネラ", 10046, 4.991, "2026/03/16 12:00:00", 2);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 12, 138201, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2002, 4, 2, "2026/06/22 11:59:59", "ネフィ＝ネラ", 10047, 3.877, "2026/03/16 12:00:00", 1);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 12, 136001, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 2002, 6, 1, "2026/06/22 11:59:59", "アラクネ", 10048, 1.71, "2026/03/16 12:00:00", 4);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, 0.0, 12, 136001, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2002, 2, 2, "2026/06/22 11:59:59", "アラクネ", 10049, 5.32, "2026/03/16 12:00:00", 5);
